import { mkdirSync, writeFileSync } from "node:fs"
import path from "node:path"
import { REPO_ROOT, loadTokens } from "./_lib.mjs"

const OUTPUT = path.join(
  REPO_ROOT,
  "apps",
  "android",
  "designsystem",
  "src",
  "main",
  "java",
  "com",
  "familyevents",
  "designsystem",
  "generated",
  "Tokens.kt"
)

const BANNER = `/*
 * AUTO-GENERATED by @family-events/design-system - DO NOT EDIT.
 * Source: packages/design-system/tokens/tokens.json
 * Regenerate: pnpm --filter @family-events/design-system build
 */
`

function pascal(name) {
  return name
    .replace(/(^|[-_\\s]+)([a-z0-9])/g, (_, __, c) => c.toUpperCase())
    .replace(/[^A-Za-z0-9]/g, "")
}

function ident(name, prefix = "") {
  const p = pascal(name)
  return /^[0-9]/.test(p) ? `${prefix}${p}` : p
}

function colorEntries(palette) {
  return Object.entries(palette)
    .map(
      ([name, token]) =>
        `        val ${ident(name)} = Color(0xFF${token.hex.replace("#", "").toUpperCase()})`
    )
    .join("\n")
}

function dpEntries(group, prefix = "") {
  return Object.entries(group)
    .map(([name, token]) => `    val ${ident(name, prefix)} = ${token.px}.dp`)
    .join("\n")
}

function textEntries(scale) {
  return Object.entries(scale)
    .map(([name, token]) => {
      const n = ident(name, "Size")
      return `    val ${n}Mobile = TextUnitBundle(${token.mobile.px}.sp, ${token.mobile.lh}f)
    val ${n}Desktop = TextUnitBundle(${token.desktop.px}.sp, ${token.desktop.lh}f)`
    })
    .join("\n")
}

function breakpointEntries(group) {
  return Object.entries(group)
    .map(([name, token]) => `    val ${ident(name, "Bp")} = ${token.px}.dp`)
    .join("\n")
}

export function buildKotlin(tokens) {
  return `${BANNER}
package com.familyevents.designsystem.generated

import androidx.compose.ui.graphics.Color
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.TextUnit
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp

object Tokens {
    object ColorLight {
${colorEntries(tokens.color.light)}
    }

    object ColorDark {
${colorEntries(tokens.color.dark)}
    }

    object Space {
${dpEntries(tokens.space, "S")}
    }

    object Radius {
${dpEntries(tokens.radius)}
    }

    data class TextUnitBundle(val size: TextUnit, val lineHeightMultiplier: Float)

    object TextScale {
${textEntries(tokens.typography.scale)}
    }

    object FontFamily {
        const val Display = "Fraunces"
        const val Body = "DM Sans"
        const val Editorial = "Newsreader"
        const val Mono = "Geist Mono"
    }

    object Touch {
        val Min: Dp = ${tokens.touch.min.px}.dp
    }

    object Breakpoint {
${breakpointEntries(tokens.breakpoint)}
    }
}
`
}

export function run() {
  const tokens = loadTokens()
  const kotlin = buildKotlin(tokens)
  mkdirSync(path.dirname(OUTPUT), { recursive: true })
  writeFileSync(OUTPUT, kotlin, "utf8")
  return OUTPUT
}

export const OUTPUT_PATH = OUTPUT

if (import.meta.url === `file://${process.argv[1]}`) {
  const out = run()
  console.log(`wrote ${path.relative(process.cwd(), out)}`)
}
